from typing import List

def maxSubArray(nums: List[int]) -> int:
    max_sum = float('-inf')
    n = len(nums)

    for i in range(n):
        for j in range(i, n):
            current_sum = sum(nums[i:j+1])
            max_sum = max(max_sum, current_sum)

    return max_sum

